// Receives the watchdog's payload on every hourly run + once at 09:00
// heartbeat. Classify, format, and decide whether to post:
//
//   mode=heartbeat, active=0   → ✅ green heartbeat (daily 'still alive')
//   mode=heartbeat, active>0   → ⚠️  yellow 'N alerts still firing'
//   mode=incremental, new>0    → 🚨 red 'new alert(s) firing'
//   mode=incremental, cleared>0→ ✅ green 'N alert(s) cleared'
//   anything else              → skip (don't spam channel every hour)
//
// Payload shape (from /usr/local/bin/td-health-check):
//   host, timestamp, mode, new_alerts[], cleared_alerts[],
//   active_alerts[], healthy_checks[], active_count, new_count, cleared_count

const body = $json.body || {};
const host = body.host || 'unknown';
const ts = body.timestamp || new Date().toISOString();
const mode = body.mode || 'incremental';
const newAlerts = body.new_alerts || [];
const clearedAlerts = body.cleared_alerts || [];
const activeAlerts = body.active_alerts || [];
const healthy = body.healthy_checks || [];
const activeCount = body.active_count || 0;
const newCount = body.new_count || 0;
const clearedCount = body.cleared_count || 0;

const fmtTime = (iso) => {
  try {
    const d = new Date(iso);
    return d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', timeZoneName: 'short' });
  } catch { return iso; }
};

const fmtHealthyList = (items) => {
  if (!items || items.length === 0) return '_(none reported)_';
  return items.map(h => `  ✓ ${h}`).join('\n');
};

let text = null;
let channel = 'bot';  // patched at import time by setup-n8n.sh if you want a different channel

if (mode === 'heartbeat') {
  if (activeCount === 0) {
    text = `:white_check_mark: **${host}** — daily heartbeat, all systems green @ ${fmtTime(ts)}\n\n` +
           `**Checks passing:**\n${fmtHealthyList(healthy)}\n\n` +
           `_Next heartbeat tomorrow at 09:00 local._`;
  } else {
    text = `:warning: **${host}** — daily status, ${activeCount} alert(s) still firing @ ${fmtTime(ts)}\n\n` +
           `**Currently firing:** ${activeAlerts.join(', ')}\n\n` +
           `**Checks passing:**\n${fmtHealthyList(healthy)}\n\n` +
           `_Run \`/usr/local/bin/td-health-check\` on the PVE host for details._`;
  }
} else if (mode === 'incremental') {
  if (newCount > 0) {
    const bullets = newAlerts.map(a => `  • **${a.key}** — ${a.message}`).join('\n');
    text = `:rotating_light: **${host}** — ${newCount} new alert(s) @ ${fmtTime(ts)}\n\n${bullets}`;
    if (activeCount > newCount) {
      text += `\n\n_(${activeCount - newCount} other alert(s) still firing from before — see daily heartbeat for full status.)_`;
    }
  } else if (clearedCount > 0) {
    text = `:white_check_mark: **${host}** — ${clearedCount} alert(s) cleared @ ${fmtTime(ts)}\n\n` +
           `**Resolved:** ${clearedAlerts.join(', ')}\n\n` +
           (activeCount > 0
             ? `_(${activeCount} other alert(s) still firing — daily heartbeat will summarize.)_`
             : `_All clear._`);
  }
}

// If text is still null, the hour was quiet: no new alerts, no clears, not
// heartbeat. Skip the post entirely so the channel doesn't get "all good"
// pings every hour — that's what the daily 09:00 heartbeat is for.
if (!text) {
  return [{ json: { skip: true, reason: 'no-change', mode, activeCount } }];
}

return [{ json: { skip: false, text, channel, mode, host, ts } }];
